{"title": "ptp-vis", "type": "vega", "aggs": [], "params": {"spec": "{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "description": "PTP Topology - Build 41: Descriptive field names, cleaner GROUP GAP comments, dead code removed",
  "autosize": pad,
  "padding": 50,

  "signals": [
    { "name": "TREE_Y_OFFSET", "value": 50 },
    { "name": "LABEL_COLOR", "value": "#fff" },
    { "name": "LABEL_DY_FACTOR", "value": 1.2 },
    { "name": "LAYER_SPACING", "value": 180 },

    // -- COLORS: status and link states --
    { "name": "CONVERGED_COLOR", "value": "#ccc" },
    { "name": "UNCONVERGED_COLOR", "value": "#d73027" },
    { "name": "STATUS_OK_COLOR", "value": "#41ab5d" },
    { "name": "GM_OK_COLOR", "value": "#006d2c" },
    { "name": "PASSIVE_COLOR", "value": "#ff7f00" },
    { "name": "NO_DATA_COLOR_ON", "value": "#bbbbbb" },
    { "name": "NO_DATA_COLOR_OFF", "value": "#555555" },

    // -- ANIMATION: blink toggle for missing-data indicator --
    {
      "name": "blink",
      "value": true,
      "on": [
        {"events": {"type": "timer", "throttle": 800}, "update": "!blink"}
      ]
    },

    { "name": "labels", "value": true },
    { "name": "layout", "value": "tidy" },
    { "name": "links", "value": "diagonal" },
    { "name": "pan_speed_multiplier", "value": 0.75 },
    { "name": "LEFT_PADDING", "value": 50,}

    { "name": "GM_SPACING","value": 80,},
    {"name": "MASTER_SPACING","update": "40 / max(zoom, 0.05)",},

    {
      "name": "zipper_lanes",
      "value": 1,
      "bind": {"input": "range", "min": 1, "max": 4, "step": 1, "name": "Followers per Row: "}
    },
    {
      "name": "zipper_offset",
      "value": 20,
      "bind": {"input": "range", "min": 10, "max": 50, "step": 5, "name": "Follower Spacing: "}
    },
    {
      "name": "GROUP_PADDING",
      "value": 30,
      "bind": {"input": "range", "min": 0, "max": 150, "step": 5, "name": "Group Gap: "}
    }

    // -- INTERACTIVITY: pan, zoom, hover --

    // PAN: drag to scroll the canvas

    {
      "name": "down",
      "value": null,
      // Captures mouse events
      "on": [
        {"events": "pointerup, mouseup", "update": "null"},
        {
          "events": "pointerdown",
          // If clicking a symbol, set it to null to avoid slipping
          // xy() instantly returns the current coordinate.
          // tldr if clicking a valid area, return coords as array.
          "update": "(event.item && event.item.mark.name === 'node_symbols') ? null : xy()"
        }
      ]
    },
    {
      "name": "pan_base_x",
      "value": 0,
      "on": [{"events": "pointerdown", "update": "tx"}]
    },
    {
      "name": "pan_base_y",
      "value": 0,
      "on": [{"events": "pointerdown", "update": "ty"}]
    },
    {
      "name": "delta",
      "value": [0, 0],
      "on": [{"events": [{"source": "window", "type": "pointermove", "consume": true, "between": [{"type": "pointerdown"}, {"source": "window", "type": "pointerup"}]}
      ], 
      // Calculates the diff between 
      "update": "down ? [down[0]-x(), down[1]-y()] : [0,0]"}]
    },

    // ZOOM: scroll wheel toward cursor; zoom-out re-centers on canvas
    {

      "name": "anchor", 
      "value": [0, 0], 
      "on": [
        {
          "events": "wheel!",
          // If zooming in (less than 0), zoom towards cursor
          // If zooming out, zoom towards the center (width/2, height/2)
          "update": "event.deltaY < 0 ? [x(), y()] : [width/2, height/2]" 
        },
      ]
    },
    {
      "name": "zoom_factor", 
      "value": 1, 
      "on": [
        {
          "events": "wheel!",
          "force": true,
          // Return 1 if trying to zoom past 100 or below 0.2, blocking further zoom inputs.
          // Otherwise, apply smoothing

          // Browser returns deltaMode (0 for pixels, 1 for lines)
          // Applying pow(16) on the deltamode normalizes everything to pixels
          // 1.001 is the exponential growth of each zoom interval so it is smooth relative
          // to the current size.

          "update": "((zoom >= 100 && event.deltaY < 0) || (zoom <= 0.2 && event.deltaY > 0)) ? 1 : pow(1.001, event.deltaY * pow(16, event.deltaMode))"
        }
      ]
    },
    {
      // Track zoom state in zoom_factor signal
      "name": "zoom", 
      "value": 1, 
      "on": [{"events": {"signal": "zoom_factor"}, "update": "clamp(zoom / zoom_factor, 0.2, 100)"}]
    },
    {
      "name": "tx", 
      "value": 0, 
      "on": [
        {"events": {"signal": "delta"}, "update": "pan_base_x - delta[0] * pan_speed_multiplier"}, 
        // Transformation, calculates the distance between chart edge and the mouse (anchor)
        // Scale the distance based on how much zoom just changed, and then add the scaled distance back to the mouse position.
        // This basically updates the chart position while it is scaling, making it look like focalized zoom.
        {"events": {"signal": "zoom_factor"}, "update": "anchor[0] + (tx - anchor[0]) / zoom_factor"}
      ]
    },
    {
      "name": "ty", 
      "value": 0, 
      "on": [
        {"events": {"signal": "delta"}, "update": "pan_base_y - delta[1] * pan_speed_multiplier"}, 
        {"events": {"signal": "zoom_factor"}, "update": "anchor[1] + (ty - anchor[1]) / zoom_factor"}
      ]
    },
    {
      "name": "hover", 
      "value": null, 
      "on": [
        {"events": "symbol:mouseover", "update": "datum"},
        {"events": "symbol:mouseout", "update": "null"},
        {"events": "wheel, mousedown", "update": "null"}
      ]
    },
    // TOOLTIP: builds a string array for hover display
    // Structure: grandmaster -> master -> slave, with optional port-state rows.
    {
      "name": "tooltip_data",
      "update": "hover ? (hover.type === 'grandmaster' ? (hover.has_no_port_data ? ['Device: ' + hover.display_name, 'Role: ' + hover.type, 'Status: ' + (hover.is_passive ? 'Passive' : (hover.status_value === 1 ? 'Unconverged Followers' : 'No unconverged followers')), 'Error: No port data available', '---', 'Port 1: ' + (hover.clock_data ? hover.clock_data.port_1 : 'NO DATA'), 'Port 2: ' + (hover.clock_data ? hover.clock_data.port_2 : 'NO DATA'), 'Port 3: ' + (hover.clock_data ? hover.clock_data.port_3 : 'NO DATA'), 'Port 4: ' + (hover.clock_data ? hover.clock_data.port_4 : 'NO DATA')] : ['Device: ' + hover.display_name, 'Role: ' + hover.type, 'Status: ' + (hover.is_passive ? 'Passive' : (hover.status_value === 1 ? 'Unconverged Followers' : 'No unconverged followers')), '---', 'Port 1: ' + (hover.clock_data ? hover.clock_data.port_1 : 'NO DATA'), 'Port 2: ' + (hover.clock_data ? hover.clock_data.port_2 : 'NO DATA'), 'Port 3: ' + (hover.clock_data ? hover.clock_data.port_3 : 'NO DATA'), 'Port 4: ' + (hover.clock_data ? hover.clock_data.port_4 : 'NO DATA')]) : (hover.type === 'master' ? (hover.has_no_port_data ? ['Device: ' + hover.display_name, 'Role: ' + hover.type, 'Status: ' + (hover.is_passive ? 'Passive' : (hover.status_value === 1 ? 'Unconverged Followers' : 'No unconverged followers')), 'Connected To: ' + hover.parent, 'Error: No port data available', '---', 'Port 1: ' + (hover.clock_data ? hover.clock_data.port_1 : 'NO DATA'), 'Port 2: ' + (hover.clock_data ? hover.clock_data.port_2 : 'NO DATA'), 'Port 3: ' + (hover.clock_data ? hover.clock_data.port_3 : 'NO DATA'), 'Port 4: ' + (hover.clock_data ? hover.clock_data.port_4 : 'NO DATA')] : ['Device: ' + hover.display_name, 'Role: ' + hover.type, 'Status: ' + (hover.is_passive ? 'Passive' : (hover.status_value === 1 ? 'Unconverged Followers' : 'No unconverged followers')), 'Connected To: ' + hover.parent, '---', 'Port 1: ' + (hover.clock_data ? hover.clock_data.port_1 : 'NO DATA'), 'Port 2: ' + (hover.clock_data ? hover.clock_data.port_2 : 'NO DATA'), 'Port 3: ' + (hover.clock_data ? hover.clock_data.port_3 : 'NO DATA'), 'Port 4: ' + (hover.clock_data ? hover.clock_data.port_4 : 'NO DATA')]) : ['Device: ' + hover.device_name, 'Type: ' + (hover.device_type || 'Unknown Device'), 'Role: ' + hover.type, 'ID: ' + hover.id, 'Status: ' + hover.final_status, 'Connected To: ' + hover.parent])) : []"
    },
    {"name": "show_master_labels", "update": "zoom > 1.5"},
    {"name": "show_slave_labels", "update": "zoom > 25"}
  ],

  "data": [
    // -- MANUAL NAMES: device name + group + role overrides --
    {
      "name": "manual_names",
      "values": [
        {"ids": ["00-02-C5-FF-FE-24-0B-3C", "00-02-C5-FF-FE-24-0B-3D"], "name": "7N.MSC.003.GM.A", "group_id": "GM", "role": "grandmaster"},
        {"ids": ["00-02-C5-FF-FE-24-0B-4E", "00-02-C5-FF-FE-24-0B-4F"], "name": "7N.MSC.003.GM.B", "group_id": "GM", "role": "grandmaster"},
        {"ids": ["00-02-C5-FF-FE-24-0B-12", "00-02-C5-FF-FE-24-0B-13"], "name": "7N.MSC.027.GM.C", "group_id": "GM", "role": "grandmaster"},
        {"ids": ["00-02-C5-FF-FE-24-0B-60", "00-02-C5-FF-FE-24-0B-61"], "name": "7N.MSC.027.GM.D", "group_id": "GM", "role": "grandmaster"},

        {"ids": ["00-02-C5-FF-FE-24-0B-5A", "00-02-C5-FF-FE-24-0B-5B"], "name": "7N.MSC.079.BC.A", "group_id": "7N-BC-1", "role": "master"},
        {"ids": ["00-02-C5-FF-FE-24-0B-2A", "00-02-C5-FF-FE-24-0B-2B"], "name": "7N.MSC.079.BC.B", "group_id": "7N-BC-1", "role": "master"},

        {"ids": ["00-02-C5-FF-FE-2A-85-08", "00-02-C5-FF-FE-2A-85-09"], "name": "7N.MSC.079.BC.C", "group_id": "7N-BC-2", "role": "master"},
        {"ids": ["00-02-C5-FF-FE-2A-75-04", "00-02-C5-FF-FE-2A-75-05"], "name": "7N.MSC.079.BC.D", "group_id": "7N-BC-2", "role": "master"},

        {"ids": ["00-02-C5-FF-FE-2D-7F-D9", "00-02-C5-FF-FE-2D-7F-DA"], "name": "7N.MSC.003.BC.E", "group_id": "7N-BC-3", "role": "master"},
        {"ids": ["00-02-C5-FF-FE-2D-82-DB", "00-02-C5-FF-FE-2D-82-DC"], "name": "7N.MSC.027.BC.E", "group_id": "7N-BC-3", "role": "master"},

        {"ids": ["00-02-C5-FF-FE-32-DE-9F", "00-02-C5-FF-FE-32-DE-A0"], "name": "7N.MSC.003.BC.F", "group_id": "7N-BC-4", "role": "master"},
        {"ids": ["00-02-C5-FF-FE-32-DF-89", "00-02-C5-FF-FE-32-DF-8A"], "name": "7N.MSC.027.BC.F", "group_id": "7N-BC-4", "role": "master"},

        {"ids": ["00-02-C5-FF-FE-20-33-6A", "00-02-C5-FF-FE-20-33-6B"], "name": "7N.MSC.003.BC.G", "group_id": "7N-BC-5", "role": "master"},
        {"ids": ["00-02-C5-FF-FE-33-77-D7", "00-02-C5-FF-FE-33-77-D8"], "name": "7N.MSC.027.BC.G", "group_id": "7N-BC-5", "role": "master"},

        {"ids": ["00-02-C5-FF-FE-3F-D7-44", "00-02-C5-FF-FE-3F-D7-45"], "name": "7S-MSC-068A-GM-A", "group_id": "7SGM", "role": "grandmaster"},
        {"ids": ["00-02-C5-FF-FE-3F-D7-80", "00-02-C5-FF-FE-3F-D7-81"], "name": "7S-MSC-068A-GM-B", "group_id": "7SGM", "role": "grandmaster"},

        {"ids": ["00-02-C5-FF-FE-24-0B-84"], "name": "SEC-A", "group_id": "SEC"},
              ]
    },
    {
      "name": "manual_names_flat",
      "source": "manual_names",
      "transform": [
        {"type": "flatten", "fields": ["ids"], "as": ["id"]}
      ]
    },


    // -- MAC INVENTORY: maps port MACs to device names -- â€” maps port MACs to parent device names
    {
      "name": "mac_inventory",
      "url": {
        "%timefield%": "",
        "index": "mac-inventory-results",
        "body": {
          "size": 10000,
          "sort": [{"@timestamp": "desc"}],
          "_source": ["mac_address", "annotation.general.device_name", "host.ip"]
        }
      },
      "format": {"type": "json", "property": "hits.hits"},
      "transform": [
        {"type": "formula", "as": "mac",          "expr": "lower(replace(datum._source.mac_address, '-', ':'))"},
        {"type": "formula", "as": "inv_dev_name", "expr": "(datum._source.annotation && datum._source.annotation.general && datum._source.annotation.general.device_name) ? datum._source.annotation.general.device_name : (datum._source.host ? datum._source.host.ip : datum._source['host.ip'])"}
      ]
    },
    // -- ELASTICSEARCH: latest PTP metrics per device --
    // Extract the fields I need
    {
      "name": "source_hits",
      "url": {
        "%timefield%": "@timestamp",
        "index": "log-metric-p-ptpmetrics-*",
        "body": {
          "size": 0, // We only care about the aggregation result
          "aggs": {
            "by_device": {
              "terms": {
                "field": "host.ip",
                "size": 3000
              },
              "aggs": {
                "latest_log": {
                  "top_hits": {
                    "size": 1,
                    "sort": [{"@timestamp": {"order": "desc"}}]
                  }
                }
              }
            }
          }
        }
      },
      "format": {"property": "aggregations.by_device.buckets"},
      "transform": [
        // 0. Extract the latest source document from the top hit
        {
          "type": "formula",
          "as": "_source",
          "expr": "datum.latest_log.hits.hits[0]._source"
        },

        // 1. Extract raw MACs from that latest source
        {
          "type": "formula", 
          "as": "raw_master_mac", 
          "expr": "datum._source.ptpmetrics && datum._source.ptpmetrics.ptpstatus ? datum._source.ptpmetrics.ptpstatus.s_master_identity : null"
        },
        {
          "type": "formula", 
          "as": "raw_gm_mac", 
          "expr": "datum._source.ptpmetrics && datum._source.ptpmetrics.ptpstatus ? datum._source.ptpmetrics.ptpstatus.s_grandmaster_identity : null"
        },

        // 2. Lookup the Device Name from the manual_names list
        {"type": "lookup", "from": "manual_names_flat", "key": "id", "fields": ["raw_master_mac"], "as": ["master_lookup"]},
        {"type": "lookup", "from": "manual_names_flat", "key": "id", "fields": ["raw_gm_mac"], "as": ["gm_lookup"]},
        // 3. Normalise EUI-64 clock identity to 6-byte colon MAC for inventory lookup
        {"type": "formula", "as": "mac_norm_master", "expr": "datum.raw_master_mac ? (length(datum.raw_master_mac) > 17 ? lower(substring(datum.raw_master_mac,0,2))+':'+lower(substring(datum.raw_master_mac,3,5))+':'+lower(substring(datum.raw_master_mac,6,8))+':'+lower(substring(datum.raw_master_mac,15,17))+':'+lower(substring(datum.raw_master_mac,18,20))+':'+lower(substring(datum.raw_master_mac,21,23)) : lower(replace(datum.raw_master_mac, '-', ':'))) : null"},
        {"type": "formula", "as": "mac_norm_gm",     "expr": "datum.raw_gm_mac ? (length(datum.raw_gm_mac) > 17 ? lower(substring(datum.raw_gm_mac,0,2))+':'+lower(substring(datum.raw_gm_mac,3,5))+':'+lower(substring(datum.raw_gm_mac,6,8))+':'+lower(substring(datum.raw_gm_mac,15,17))+':'+lower(substring(datum.raw_gm_mac,18,20))+':'+lower(substring(datum.raw_gm_mac,21,23)) : lower(replace(datum.raw_gm_mac, '-', ':'))) : null"},
        {"type": "lookup", "from": "mac_inventory", "key": "mac", "fields": ["mac_norm_master"], "as": ["master_inv_lookup"]},
        {"type": "lookup", "from": "mac_inventory", "key": "mac", "fields": ["mac_norm_gm"],     "as": ["gm_inv_lookup"]},

        // 3. Set the official IDs to the Name (if found), otherwise fallback to MAC
        {"type": "formula", "as": "master_id", "expr": "datum.master_lookup ? datum.master_lookup.name : (datum.master_inv_lookup && datum.master_inv_lookup.inv_dev_name ? datum.master_inv_lookup.inv_dev_name : datum.raw_master_mac)"},
        {"type": "formula", "as": "gm_id", "expr": "datum.gm_lookup ? datum.gm_lookup.name : (datum.gm_inv_lookup && datum.gm_inv_lookup.inv_dev_name ? datum.gm_inv_lookup.inv_dev_name : datum.raw_gm_mac)"},

        // 4. Map existing formulas to the latest source
        {"type": "formula", "as": "slave_id", "expr": "datum.key"}, // The bucket key is the host.ip

        {"type": "formula", "as": "ptp_status", "expr": "datum._source.ptpmetrics && datum._source.ptpmetrics.ptpstatus ? datum._source.ptpmetrics.ptpstatus.s_ptp_status : 'Unknown'"},

        {"type": "formula", "as": "status_value", "expr": "datum.ptp_status !== 'Converged' && datum.ptp_status !== 'Locked' ? 1 : 0"},

        // Grab device metadata from the latest hit
        {"type": "formula", "as": "device_name", "expr": "datum._source.annotation && datum._source.annotation.general ? datum._source.annotation.general.device_name : null"},

        {"type": "formula", "as": "device_type", "expr": "datum._source.annotation && datum._source.annotation.general ? datum._source.annotation.general.device_type : null"},

        {"type": "filter", "expr": "datum.master_id != null"}
      ]
    },
    {
      "name": "clock_states",
      "url": {
        "%timefield%": "@timestamp",
        "index": "log-metric-p-msc-*", 
        "body": {
          "size": 0,
          "aggs": {
            "by_device": {
              "terms": {
                "field": "annotation.general.device_name.keyword",
                "size": 3000
              },
              "aggs": {
                "latest_log": {
                  "top_hits": {
                    "size": 1,
                    "sort": [{"@timestamp": {"order": "desc"}}],
                    "_source": [
                      "annotation.general.device_name",
                      "msc.snmp.s_port_1_state",
                      "msc.snmp.s_port_2_state",
                      "msc.snmp.s_port_3_state",
                      "msc.snmp.s_port_4_state"
                    ]
                  }
                }
              }
            }
          }
        }
      },
      "format": {"property": "aggregations.by_device.buckets"},
      "transform": [
        {
          "type": "formula",
          "as": "_source",
          "expr": "datum.latest_log.hits.hits[0]._source"
        },
        {
          "type": "formula", 
          "as": "device_name", 
          "expr": "datum._source.annotation && datum._source.annotation.general ? datum._source.annotation.general.device_name : null"
        },
        {
          "type": "formula", 
          "as": "port_1", 
          "expr": "datum._source.msc && datum._source.msc.snmp ? datum._source.msc.snmp.s_port_1_state : 'Unknown'"
        },
        {
          "type": "formula", 
          "as": "port_2", 
          "expr": "datum._source.msc && datum._source.msc.snmp ? datum._source.msc.snmp.s_port_2_state : 'Unknown'"
        },
        {
          "type": "formula", 
          "as": "port_3", 
          "expr": "datum._source.msc && datum._source.msc.snmp ? datum._source.msc.snmp.s_port_3_state : 'Unknown'"
        },
        {
          "type": "formula", 
          "as": "port_4", 
          "expr": "datum._source.msc && datum._source.msc.snmp ? datum._source.msc.snmp.s_port_4_state : 'Unknown'"
        },
        {
          "type": "formula", 
          "as": "is_passive", 
          "expr": "datum.port_1 != 'PTP master' && datum.port_2 != 'PTP master' && datum.port_3 != 'PTP master' && datum.port_4 != 'PTP master'"
        }
      ]
    },
    // -- SLAVE NODES: inferred from the PTP poller data --

    // Inferring the hierarchy from slaves to masters
    {
      "name": "nodes_slaves",
      "source": "source_hits",
      "transform": [
        // Project generates a dataset out of fields provided, grooming the data further into id, parent, status, and status value. Id and parent are required keywords of vega.
        {"type": "project", "fields": ["slave_id", "master_id", "ptp_status", "status_value", "device_name", "device_type"], "as": ["id", "parent", "ptp_status", "status_value", "device_name", "device_type"]},
        // Hardcode these entities as slaves for easier styling later
        {"type": "formula", "as": "type", "expr": "'slave'"}
      ]
    },
    // -- MASTER NODES: inferred from slave parent references --
    // If a slave is connected to a master, then the master must exist (inferred)
    // Manually create a node if so.
    {
      "name": "nodes_masters",
      "source": "source_hits",
      "transform": [
        // Deduplicate/sort all hosts by one ID so we don't have a million of the same master node.
        {"type": "aggregate", "groupby": ["master_id"], "fields": ["gm_id", "status_value"], "ops": ["max", "max"], "as": ["gm_id", "status_value"]},
        // Determine the masters parent (GM or Root). If the reported master is the same as GM, then its a GM.
        {"type": "formula", "as": "parent", "expr": "(datum.gm_id && datum.gm_id != datum.master_id) ? datum.gm_id : 'GLOBAL_ROOT'"},
        // Format into id's, parent, and status value like we did for slaves
        {"type": "project", "fields": ["master_id", "parent", "status_value"], "as": ["id", "parent", "status_value"] },
        // Type as GM or Master based on if its connected to Global Root or not.
        {"type": "formula", "as": "type", "expr": "datum.parent === 'GLOBAL_ROOT' ? 'grandmaster' : 'master'"},
        // Nulling device name/type since I don't have them yet in this dataset.
        {"type": "formula", "as": "device_name", "expr": "null"},
        {"type": "formula", "as": "device_type", "expr": "null"}
      ]
    },
    // -- GRANDMASTER NODES: inferred from master GM references --
    // Inferring just like we did for masters.
    {
      "name": "nodes_gms",
      "source": "source_hits",
      "transform": [
        // Create new node here only if the gm_id is unique/doesn't match an existing master.
        {"type": "filter", "expr": "datum.gm_id != null && datum.gm_id != datum.master_id"},
        // Deduplicate as was done for masters.
        {"type": "aggregate", "groupby": ["gm_id"], "fields": ["status_value"], "ops": ["max"], "as": ["status_value"]},

        // Format into the expected vega type (ID)
        {"type": "project", "fields": ["gm_id", "status_value"], "as": ["id", "status_value"]},

        // Link GM's to root
        {"type": "formula", "as": "parent", "expr": "'GLOBAL_ROOT'"},
        {"type": "formula", "as": "type", "expr": "'grandmaster'"},
        {"type": "formula", "as": "device_name", "expr": "null"},
        {"type": "formula", "as": "device_type", "expr": "null"}
      ]
    },

    {
